example.code:
var app = builder.Build();
app.UseRedisRateLimiting();
app.MapControllers();
app.Run();

builder.Services.AddRedisRateLimiting("localhost:6379", options =>
{
    options.PermitLimit = 60;
    options.Window = TimeSpan.FromMinutes(1);
    options.ClientIdExtractor = ctx => ctx.Request.Headers["X-API-Key"].FirstOrDefault() ?? "anonymous";
});

// Use an API key header as the client identifier:
options.ClientIdExtractor = context =>
    context.Request.Headers["X-API-Key"].FirstOrDefault() ?? "anonymous";
